############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.126) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserNumberWithUnits.pl", "contextCurrency.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $name = randomPerson(); $initial = random(800,1000,20); Context("Currency")->flags->set(trimTrailingZeros => 1); $start = Currency($initial); $rate = random(200,250,5); $speed = Currency($rate); $final = random(80,100,10); $end = Currency($final); $solution = -($final - $initial)/$rate; $time = NumberWithUnits("$solution hr");
############################################################ # Body ############################################################
BEGIN_PGML At a recent trip to the casino, [$name] brought [`[$start]`] in cash. [$name->Subject] knew that [$name->subject] needed to hold on to [`[$end]`] to pay for dinner later. [$name] had rough luck and was losing money at the slot machines at an average rate of [`[$speed]`] per hour. How long was [$name] gambling before [$name->subject] had to stop?
[_]{$time}{20}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
